class Solution:
    def lexPalindromicPermutation(self, s, target):
        from collections import Counter
        n = len(s)
        cnt = Counter(s)
        odd = [c for c in cnt if cnt[c] % 2 == 1]
        if len(odd) > 1:
            return ''
        center = odd[0] if odd else ''
        pb = {c: cnt[c] // 2 for c in cnt}
        h = (n + 1) // 2
        res = [None]
        half = [None] * h
        def build():
            if n % 2 == 1:
                left = ''.join(half[:h - 1])
                return left + half[h - 1] + left[::-1]
            left = ''.join(half)
            return left + left[::-1]
        def dfs(pos, tight):
            if res[0] is not None:
                return
            if pos == h:
                full = build()
                if full > target:
                    res[0] = full
                return
            if n % 2 == 1 and pos == h - 1:
                half[pos] = center
                dfs(pos + 1, tight and center == target[pos])
                half[pos] = None
                return
            for c in sorted(k for k in pb if pb[k] > 0):
                if tight and c < target[pos]:
                    continue
                pb[c] -= 1
                half[pos] = c
                dfs(pos + 1, tight and c == target[pos])
                half[pos] = None
                pb[c] += 1
                if res[0] is not None:
                    return
        dfs(0, True)
        return res[0] if res[0] is not None else ''

