    def lexPalindromicPermutation(self, s, target):
        from collections import Counter
        n = len(s)
        cnt = Counter(s)
        odd = [c for c in cnt if cnt[c] % 2 == 1]
        if len(odd) > 1:
            return ''
        center = odd[0] if odd else ''
        pb = [0] * 26
        for c in cnt:
            pb[ord(c) - 97] = cnt[c] // 2
        L = n // 2
        def rest(b):
            return ''.join(chr(97 + i) * b[i] for i in range(26))
        def full_of(H):
            if n % 2 == 1:
                return H + center + H[::-1]
            return H + H[::-1]
        best = None
        for p in range(L - 1, -1, -1):
            temp = pb[:]
            ok = True
            for i in range(p):
                idx = ord(target[i]) - 97
                if temp[idx] <= 0:
                    ok = False
                    break
                temp[idx] -= 1
            if not ok:
                continue
            tp = ord(target[p]) - 97
            chosen = -1
            for c in range(tp + 1, 26):
                if temp[c] > 0:
                    chosen = c
                    break
            if chosen == -1:
                continue
            temp[chosen] -= 1
            H = target[:p] + chr(97 + chosen) + rest(temp)
            full = full_of(H)
            if full > target and (best is None or full < best):
                best = full
        temp = pb[:]
        ok = True
        for i in range(L):
            idx = ord(target[i]) - 97
            if temp[idx] <= 0:
                ok = False
                break
            temp[idx] -= 1
        if ok:
            H = target[:L]
            full = full_of(H)
            if full > target and (best is None or full < best):
                best = full
        return best if best is not None else ''

